import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../core/services/auth.service';

interface NavItem {
  label: string;
  path: string;
  icon: string;
}

// Persistent app shell for BeehiveWatch. The brand header renders the literal
// string "BeehiveWatch" (SMOKE_MARKER). Public nav (Bills, Legislators, Conflicts)
// is always visible; editor-only Login/Logout is conditional on auth state.
@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css',
})
export class LayoutComponent {
  readonly nav: NavItem[] = [
    { label: 'Bills', path: '/bills', icon: '📜' },
    { label: 'Legislators', path: '/legislators', icon: '🏛️' },
    { label: 'Conflicts', path: '/conflicts', icon: '⚠️' },
  ];

  readonly isEditor = this.auth.isEditor;
  readonly user = this.auth.user;

  constructor(private auth: AuthService) {}

  logout(): void {
    this.auth.logout();
  }
}
